-- 6. Atualiza % de atingimento dos objetivos (média do progresso dos projetos)
update objetivos o
set pct_atual = coalesce((
  select round(avg(p.pct))::smallint
  from projetos p
  where p.objetivo_id = o.id
), 0)
where o.municipio_id = '00000000-0000-0000-0000-000000000001';

-- 7. Conferência
select 'eixos' as tabela, count(*) from eixos where municipio_id = '00000000-0000-0000-0000-000000000001'
union all select 'objetivos', count(*) from objetivos where municipio_id = '00000000-0000-0000-0000-000000000001'
union all select 'secretarias', count(*) from secretarias where municipio_id = '00000000-0000-0000-0000-000000000001'
union all select 'projetos', count(*) from projetos where municipio_id = '00000000-0000-0000-0000-000000000001';
